module puf_clk_mux
   (clk,
    clk_hi,
    clk_lo,
    rst,
    clk_out);
  input clk;
  input clk_hi;
  input clk_lo;
  input rst;
  output clk_out;

  wire clk;
  wire clk_hi;
  wire clk_lo;
  wire clk_out;
  wire clk_out_reg_C_n_0;
  wire clk_out_reg_LDC_i_1_n_0;
  wire clk_out_reg_LDC_i_2_n_0;
  wire clk_out_reg_LDC_n_0;
  wire clk_out_reg_P_n_0;
  wire rst;

  LUT3 #(
    .INIT(8'hB8)) 
    clk_out_INST_0
       (.I0(clk_out_reg_P_n_0),
        .I1(clk_out_reg_LDC_n_0),
        .I2(clk_out_reg_C_n_0),
        .O(clk_out));
  FDCE #(
    .INIT(1'b0)) 
    clk_out_reg_C
       (.C(clk),
        .CE(1'b1),
        .CLR(clk_out_reg_LDC_i_2_n_0),
        .D(clk_lo),
        .Q(clk_out_reg_C_n_0));
  (* XILINX_LEGACY_PRIM = "LDC" *) 
  (* XILINX_TRANSFORM_PINMAP = "VCC:GE" *) 
  LDCE #(
    .INIT(1'b0)) 
    clk_out_reg_LDC
       (.CLR(clk_out_reg_LDC_i_2_n_0),
        .D(1'b1),
        .G(clk_out_reg_LDC_i_1_n_0),
        .GE(1'b1),
        .Q(clk_out_reg_LDC_n_0));
  LUT2 #(
    .INIT(4'h8)) 
    clk_out_reg_LDC_i_1
       (.I0(rst),
        .I1(clk_hi),
        .O(clk_out_reg_LDC_i_1_n_0));
  LUT2 #(
    .INIT(4'h2)) 
    clk_out_reg_LDC_i_2
       (.I0(rst),
        .I1(clk_hi),
        .O(clk_out_reg_LDC_i_2_n_0));
  FDPE #(
    .INIT(1'b1)) 
    clk_out_reg_P
       (.C(clk),
        .CE(1'b1),
        .D(clk_lo),
        .PRE(clk_out_reg_LDC_i_1_n_0),
        .Q(clk_out_reg_P_n_0));
endmodule

